export const COURSES: Course[] = [
  {
    slug: 'cannabis-foundations', number: '01', title: 'Cannabis Foundations', shortTitle: 'Foundations',
    description: 'Build a precise vocabulary and understand the plant, its products, and the difference between evidence and folklore.',
    level: 'Foundation', accent: '#62c68b',
    modules: [
      { title: 'Orientation', description: 'Start with language, context, and scientific literacy.', lessons: [
        { slug: 'what-is-cannabis', title: 'What is cannabis?', summary: 'A clear introduction to the plant, hemp, drug-type cannabis, and the language used across science and culture.', duration: '18 min',
          objectives: ['Distinguish the plant from its many products', 'Use cannabis terminology accurately', 'Recognize why common labels can mislead'], keyTerms: ['Cannabis', 'Hemp', 'Cultivar', 'Chemotype', 'Trichome'], reviewedAt: '16 July 2026',
          sections: [
            { id: 'one-plant-many-uses', title: 'One plant, many uses', paragraphs: ['Cannabis is a genus of flowering plants cultivated for fibre, seed, medicines, intoxicating products, and research. “Cannabis” can therefore describe a living plant, dried flower, resin, an extract, or a regulated medicine. Good education names the specific material rather than treating all of these as interchangeable.'], evidence: 'established', citationIds: ['nap-2024'] },
            { id: 'labels', title: 'Beyond indica and sativa', paragraphs: ['Commercial labels such as indica, sativa, and hybrid do not reliably predict a person’s experience. Modern plants are extensively hybridized, and effects depend on chemical composition, dose, route, prior exposure, biology, setting, and expectations. Chemotype and laboratory composition are more informative than a marketing category.'], evidence: 'supported', citationIds: ['nap-2024'], callout: { title: 'A better question', body: 'Instead of asking “Is it indica or sativa?”, ask what cannabinoids are present, at what concentrations, how the product was tested, and what dose is being considered.', tone: 'note' } },
            { id: 'nigerian-language', title: 'Language in Nigeria', paragraphs: ['Terms such as igbo, weed, marijuana, hemp, Colorado and synthetic cannabinoids may refer to very different materials depending on the speaker and location. A safety-first portal defines the substance before discussing effects or law.'], callout: { title: 'Local context', body: 'Cannabis remains legally controlled in Nigeria. Educational content is not an instruction to possess, cultivate, or supply it.', tone: 'nigeria' } },
            { id: 'taxonomy', title: 'Species, varieties and classification', paragraphs: ['Cannabis classification remains debated. Botanical names, legal definitions, commercial categories and breeding language answer different questions. “Hemp” is usually a legal or agronomic category defined by intended use or THC limits, not a completely separate plant with no shared ancestry.', 'Cultivar names can carry cultural and commercial meaning, but names are not chemical assays. Two products sharing a name may differ, while differently named products may have similar measured profiles.'] , evidence: 'supported', citationIds: ['nap-2024'] },
            { id: 'product-map', title: 'From plant to product', paragraphs: ['Common product categories include flower, resin, concentrates, oral oils, capsules, foods, tincture-like liquids, topicals and regulated cannabinoid medicines. Processing can concentrate compounds, remove them, introduce contaminants or change how quickly exposure occurs.', 'A safe description names the material, preparation, measured composition, route and dose. The word cannabis alone is too broad for many medical or scientific claims.'], evidence: 'established', citationIds: ['solmi-2023'] },
          ] },
        { slug: 'how-to-read-cannabis-research', title: 'How to read cannabis research', summary: 'Learn why a cell study, survey, clinical trial, and systematic review cannot support the same claim.', duration: '24 min', objectives: ['Identify common study designs', 'Interpret association versus causation', 'Read evidence labels'], keyTerms: ['Clinical trial', 'Systematic review', 'Confounding', 'Certainty'], reviewedAt: '16 July 2026', sections: [
          { id: 'hierarchy', title: 'Evidence is a ladder', paragraphs: ['Laboratory and animal studies can reveal mechanisms, but they do not prove that a product is safe or effective in people. Randomized trials can test defined interventions. Systematic reviews synthesize multiple studies, while consensus reports consider evidence alongside public-health implementation.'], evidence: 'established', citationIds: ['solmi-2023'] },
          { id: 'precision', title: 'Name the intervention', paragraphs: ['“Cannabis works” is rarely a scientifically useful conclusion. Research may examine purified CBD, synthetic THC, a THC:CBD spray, smoked flower, or an oral extract. Findings from one formulation should not automatically be transferred to another.'], evidence: 'established', citationIds: ['solmi-2023'], callout: { title: 'Efifya evidence labels', body: 'Established, supported, preliminary, and inconclusive describe confidence—not whether a result sounds positive or negative.', tone: 'note' } },
          { id: 'association-causation', title: 'Association is not automatically causation', paragraphs: ['Observational studies can identify patterns in real populations, but exposure may be entangled with age, tobacco or alcohol use, income, illness, trauma, access to care and reasons for using cannabis. Statistical adjustment can reduce some confounding but cannot guarantee that every difference has been removed.', 'Causal confidence grows when different designs converge, temporality is clear, dose-response patterns are plausible and alternative explanations become less likely. A single correlation rarely settles a complex health question.'], evidence: 'established', citationIds: ['solmi-2023'] },
          { id: 'numbers', title: 'Read beyond statistical significance', paragraphs: ['A small p-value does not show that an effect is large, useful or unbiased. Look for absolute risks, effect sizes, confidence intervals, missing data, sample size, preregistration and whether the measured outcome matters to patients.', 'For reviews, ask how studies were selected, whether poor-quality studies dominate, how different the interventions were and whether publication bias was assessed. “Meta-analysis” is a method, not an automatic guarantee of truth.'], evidence: 'established', citationIds: ['ahrq-2025'] },
          { id: 'funding-and-transfer', title: 'Funding, conflicts and transferability', paragraphs: ['Industry, advocacy and institutional incentives can influence the questions asked, comparators chosen and results emphasized. A conflict does not invalidate a study, but it should shape scrutiny and disclosure.', 'Also ask whether the participants, products, healthcare setting and legal environment resemble the question you care about. Findings from a standardised pharmaceutical product in a controlled trial may not transfer to an untested Nigerian street product.'], evidence: 'established', citationIds: ['nap-2024', 'cooper-barriers-2021'], callout: { title: 'Researcher lens: Ziva Cooper and Sue Sisley', body: 'Clinical cannabis researchers have documented how regulation, restricted study materials and differences between laboratory products and real markets can limit transferability.', tone: 'note' } },
        ] },
      ] },
      { title: 'Plant literacy', description: 'Understand anatomy, lifecycle, taxonomy, and chemical diversity.', lessons: [
        { slug: 'plant-anatomy', title: 'Plant anatomy and lifecycle', summary: 'Roots, stems, leaves, flowers, trichomes, reproduction, and the plant lifecycle.', duration: '22 min', objectives: ['Identify the plant’s major vegetative and reproductive structures', 'Explain where glandular trichomes occur and what they produce', 'Describe the lifecycle without relying on indica/sativa stereotypes', 'Distinguish stigmas, bracts and trichomes'], keyTerms: ['Taproot', 'Node', 'Inflorescence', 'Bract', 'Stigma', 'Trichome', 'Dioecious', 'Photoperiod'], reviewedAt: '16 July 2026', sections: [
          { id: 'roots-stems-leaves', title: 'Roots, stems and leaves', paragraphs: ['The root system anchors the plant and absorbs water and dissolved mineral nutrients. A primary root develops lateral branches whose growth depends on genetics, the physical environment and plant health. Roots also exchange signals with microorganisms in the surrounding root zone.', 'The stem supports leaves and reproductive structures while vascular tissues move water, minerals and sugars. Nodes are the points where leaves and branches emerge; the spaces between them are internodes. Leaf shape and leaflet number vary with development and genetics, so a single leaf is not a reliable guide to a plant’s chemistry or effects.'], evidence: 'supported', citationIds: ['ditchfield-2014'] },
          { id: 'flowers-and-sex', title: 'Flowers, sex expression and reproduction', paragraphs: ['Cannabis commonly produces male and female reproductive structures on separate plants, although sex expression can be more complex. Pollen-producing flowers and seed-producing flowers have different structures and roles. Pollination allows a fertilised ovule to develop into a seed.', 'The dense structure casually called a “bud” is an inflorescence: a cluster of flowers and associated bracts. The small leaf-like bract surrounds reproductive tissues and carries many glandular trichomes. The paired hairs often called pistils are more precisely stigmas, surfaces that receive pollen.'], evidence: 'supported', citationIds: ['ditchfield-2014'], callout: { title: 'Terminology check', body: 'Bracts, stigmas and trichomes are different structures. Their names are often mixed together in informal cultivation writing.', tone: 'note' } },
          { id: 'trichomes', title: 'Trichomes: chemical production and defence', paragraphs: ['Trichomes are hair-like epidermal structures. Cannabis has several trichome types, but capitate-stalked glandular trichomes on female inflorescences are especially important because their secretory heads accumulate cannabinoid acids and many volatile compounds.', 'Trichomes are part of the plant’s interaction with its environment, not containers made for human use. Their abundance, maturity and chemical composition vary across tissues, development, genotype and environment. A frosty appearance alone cannot establish potency, identity or safety.'], evidence: 'supported', citationIds: ['ditchfield-2014'] },
          { id: 'lifecycle', title: 'From seed to senescence', paragraphs: ['A simplified lifecycle includes germination, seedling establishment, vegetative growth, reproductive development and senescence. Photoperiod-sensitive plants begin reproductive development in response to night length, while so-called autoflowering types are less dependent on seasonal light cues.', 'Development is continuous rather than a set of perfectly separated stages. Water availability, root conditions, light, temperature, nutrition, pests and stress can change growth rate and final form. Calendar age alone does not describe physiological maturity.'], evidence: 'supported', citationIds: ['ditchfield-2014'] },
          { id: 'harvest-myths', title: 'What anatomy cannot tell you by itself', paragraphs: ['Stigma colour is affected by age, pollination, environment and damage. The proportion of orange or brown stigmas is therefore not a validated measure of cannabinoid potency or an exact harvest clock. Trichome appearance is also an imperfect proxy unless paired with defined sampling and chemical analysis.', 'Likewise, tall narrow-leaf and short broad-leaf forms do not reliably predict a particular subjective effect. Botanical description, genetic ancestry, chemical analysis and reported experience answer different questions and should not be collapsed into one label.'], evidence: 'supported', citationIds: ['nap-2024'], callout: { title: 'Nigeria context', body: 'Plant science is presented for education. Cannabis cultivation remains legally controlled in Nigeria.', tone: 'nigeria' } },
        ] },
      ] },
    ],
  },
  {
    slug: 'chemistry-and-the-body', number: '02', title: 'Chemistry & the Human Body', shortTitle: 'Chemistry',
    description: 'Explore cannabinoids, aromatic compounds, the endocannabinoid system, pharmacology, and why dose and route matter.', level: 'Intermediate', accent: '#d6a84b',
    modules: [{ title: 'Core chemistry', description: 'From plant compounds to human effects.', lessons: [
      { slug: 'cannabinoids-and-the-ecs', title: 'Cannabinoids and the ECS', summary: 'An evidence-aware guide to THC, CBD, receptors, endocannabinoids, and uncertainty.', duration: '25 min', objectives: ['Describe CB1 and CB2 at a high level', 'Distinguish plant and endogenous cannabinoids'], keyTerms: ['Endocannabinoid', 'CB1', 'CB2', 'THC', 'CBD'], reviewedAt: '16 July 2026', sections: [
        { id: 'ecs', title: 'A signalling system, not a simple switch', paragraphs: ['The endocannabinoid system includes signalling molecules, receptors, and enzymes distributed across the brain and body. It participates in many physiological processes, but calling it a single “balance system” oversimplifies complex, context-dependent biology.'], evidence: 'established', citationIds: ['solmi-2023'] },
        { id: 'effects', title: 'Effects depend on exposure', paragraphs: ['THC can produce intoxication and impairment. CBD is not intoxicating in the same way, but it is pharmacologically active and can cause adverse effects or interact with medicines. Product identity, dose, route, frequency, and individual vulnerability all matter.'], evidence: 'established', citationIds: ['solmi-2023'] },
        { id: 'endocannabinoids', title: 'Endocannabinoids and enzymes', paragraphs: ['The body produces signalling molecules including anandamide and 2-arachidonoylglycerol. They are synthesised and broken down on demand through multiple enzymes rather than stored and released exactly like classical neurotransmitters.', 'These signals participate in feedback across neural and immune pathways. Their presence in many tissues does not mean that increasing cannabinoid signalling is always beneficial; direction, timing, receptor and tissue all matter.'], evidence: 'supported', citationIds: ['solmi-2023'] },
        { id: 'receptors', title: 'CB1, CB2—and beyond', paragraphs: ['CB1 receptors are abundant in parts of the nervous system and contribute to THC intoxication, memory disruption, appetite and motor effects. CB2 receptors are prominent in immune-related signalling, but both receptors occur across multiple tissues.', 'Cannabinoids and related compounds may also influence other molecular targets. Reducing the entire pharmacology to “THC equals CB1 and CBD equals CB2” is inaccurate. CBD has complex, dose-dependent actions and does not simply cancel THC.'], evidence: 'supported', citationIds: ['solmi-2023'] },
        { id: 'interactions', title: 'Metabolism and medicine interactions', paragraphs: ['Cannabinoids are metabolised through liver enzyme systems that also process many medicines. CBD in particular can alter exposure to some prescribed drugs, while sedating effects can add to alcohol, opioids, antihistamines or other central nervous system depressants.', 'The practical relevance depends on product, dose, frequency, medicine and patient. A non-intoxicating label does not mean pharmacologically inactive or interaction-free.'], evidence: 'supported', citationIds: ['solmi-2023'], callout: { title: 'Medication safety', body: 'People taking prescription medicines—especially medicines with narrow safety margins—should discuss cannabinoid use with a qualified clinician or pharmacist.', tone: 'safety' } },
      ] },
      { slug: 'dose-route-and-duration', title: 'Dose, route & duration', summary: 'Why inhaled, oral, sublingual, and topical products behave differently.', duration: '19 min', objectives: ['Compare onset and duration across common routes', 'Explain why oral THC can feel different from inhaled THC', 'Recognize delayed-dose and accumulation risks'], keyTerms: ['Bioavailability', 'Onset', 'Peak effect', 'Half-life', 'First-pass metabolism'], reviewedAt: '16 July 2026', sections: [
        { id: 'route', title: 'Route changes exposure', paragraphs: ['Inhaled cannabinoids generally enter the bloodstream rapidly through the lungs. Effects may begin quickly, which changes how people perceive and adjust exposure. Smoke and aerosol also introduce route-specific respiratory considerations.', 'Swallowed cannabinoids have a slower and more variable onset because absorption and liver metabolism occur before much of the dose reaches systemic circulation. With THC, the liver forms active 11-hydroxy-THC. Delayed onset makes unplanned repeat dosing a particular concern.'], evidence: 'supported', citationIds: ['solmi-2023'] },
        { id: 'dose-is-not-a-number-alone', title: 'A dose is not a number alone', paragraphs: ['A labelled milligram amount is meaningful only when product identity and composition are reliable. Actual exposure also depends on formulation, route, food, metabolism, medicines, prior use and measurement accuracy.', 'The same numerical amount should not be assumed equivalent across inhaled flower, an oral oil and an edible. Research findings from a standardised medicine also cannot automatically be transferred to an untested commercial or street product.'], evidence: 'established', citationIds: ['solmi-2023', 'cooper-potency-2025'] },
        { id: 'duration-and-accumulation', title: 'Duration, impairment and accumulation', paragraphs: ['Subjective effects can fade before every pharmacological effect or impairment has resolved. Repeated exposure may accumulate, and cannabinoids or metabolites can remain detectable after obvious intoxication ends. Detection does not always equal current impairment, but feeling normal is not a dependable driving test.', 'Duration varies substantially, particularly with oral products. Plans involving transport, caregiving, work at height, machinery or other safety-sensitive activity should allow for uncertainty rather than relying on a fixed universal timetable.'], evidence: 'supported', citationIds: ['nap-2024'] },
        { id: 'individual-variation', title: 'Why responses differ', paragraphs: ['Age, body composition, liver function, cardiovascular and mental-health history, pregnancy, genetics, tolerance and interacting medicines may alter effects or risk. A previous uneventful experience does not guarantee that a new product or dose will behave the same way.'], evidence: 'supported', citationIds: ['solmi-2023'], callout: { title: 'Safety principle', body: 'A calculator cannot determine a universally safe or therapeutic dose. Avoid combining cannabis with alcohol or other sedating substances, and seek qualified clinical advice for medical decisions.', tone: 'safety' } },
      ] },
      { slug: 'terpenes-flavonoids-and-entourage', title: 'Terpenes, flavonoids & the entourage question', summary: 'Separate established plant chemistry from confident claims that aroma predicts a therapeutic effect.', duration: '24 min', objectives: ['Describe the biological roles of terpenes and flavonoids', 'Explain why aroma is not a clinical prescription', 'Evaluate entourage-effect claims'], keyTerms: ['Terpene', 'Terpenoid', 'Flavonoid', 'Volatility', 'Entourage effect'], reviewedAt: '16 July 2026', sections: [
        { id: 'plant-chemistry', title: 'A chemically diverse plant', paragraphs: ['Cannabis produces cannabinoids alongside volatile terpenes, flavonoids, lipids, pigments and many other compounds. Their amounts vary with genetics, tissue, development, environment, processing and storage.', 'Terpenes contribute aroma and participate in plant defence and ecological signalling. Flavonoids contribute pigmentation and other plant functions. Detecting a compound in a plant does not establish that the amount inhaled or swallowed produces a therapeutic effect in humans.'], evidence: 'established', citationIds: ['entourage-2024'] },
        { id: 'aroma-and-effects', title: 'Aroma does not prescribe an effect', paragraphs: ['Descriptors such as citrus, pine or floral can help describe sensory experience, but they do not reliably tell a person that a product will be energising, sedating or anxiolytic. Expectation, THC exposure, context and prior experience can influence reported effects.', 'Many popular terpene claims are extrapolated from isolated compounds, non-cannabis preparations, animals or laboratory concentrations. Those findings may generate hypotheses but should not be converted directly into consumer dosing advice.'], evidence: 'inconclusive', citationIds: ['entourage-2024'] },
        { id: 'entourage', title: 'What “entourage effect” can mean', paragraphs: ['The term is used for several ideas: interactions among cannabinoids, interactions between cannabinoids and terpenes, or differences between complex extracts and isolated compounds. Those are distinct hypotheses and require different tests.', 'Some cannabinoid combinations have clinically relevant interactions, but this does not prove that every whole-plant product is superior or that every terpene meaningfully steers THC. Product-specific evidence is necessary.'], evidence: 'inconclusive', citationIds: ['entourage-2024'] },
        { id: 'storage', title: 'Volatility, oxidation and storage', paragraphs: ['Heat, oxygen, light and time can alter volatile compounds and cannabinoids. A label describes a product at a particular test point, not an unchanging chemical object.', 'Storage quality matters, but smell alone cannot detect pesticides, heavy metals, microbes, residual solvents or synthetic adulterants. Sensory assessment and analytical testing answer different questions.'], evidence: 'supported', citationIds: ['nap-2024'], callout: { title: 'Use the mapper carefully', body: 'Interactive terpene diagrams are chemistry-learning tools, not medical recommendation engines.', tone: 'note' } },
      ] },
    ] }],
  },
  {
    slug: 'safety-and-health', number: '03', title: 'Safety, Health & Harm Reduction', shortTitle: 'Safety',
    description: 'Understand impairment, adverse effects, dependence, vulnerable groups, synthetic cannabinoids, and the actual state of medical evidence.', level: 'Foundation', accent: '#ef8f70',
    modules: [{ title: 'Health decisions', description: 'Separate therapeutic promise from established care.', lessons: [
      { slug: 'medical-evidence', title: 'What does the medical evidence support?', summary: 'A condition-by-condition framework for benefits, harms, approved medicines, and uncertainty.', duration: '30 min', objectives: ['Avoid broad medical claims', 'Understand evidence certainty', 'Recognize when professional care is needed'], keyTerms: ['Indication', 'Adverse event', 'Certainty', 'Contraindication'], reviewedAt: '16 July 2026', sections: [
        { id: 'not-one-treatment', title: 'Cannabis is not one treatment', paragraphs: ['Clinical evidence applies to defined cannabinoids, formulations, doses, and conditions. Benefits shown for one product or symptom do not establish that cannabis cures a disease. Evidence is more convincing for some narrowly defined indications than for many widely promoted uses.'], evidence: 'established', citationIds: ['solmi-2023', 'ahrq-2025'] },
        { id: 'pain', title: 'Chronic pain evidence', paragraphs: ['Recent living reviews report small short-term improvements for some cannabinoid products in some chronic pain populations, alongside increased dizziness, sedation, and nausea. Evidence for long-term benefit and serious harms remains limited.'], evidence: 'supported', citationIds: ['ahrq-2025'] },
        { id: 'where-evidence-is-stronger', title: 'Where evidence is comparatively stronger', paragraphs: ['Evidence and regulatory approval are clearest for specific cannabinoid medicines in narrow indications, such as certain treatment-resistant seizure disorders and selected symptoms addressed by standardised products. This does not establish that smoked flower or an unregulated CBD oil is equivalent.', 'For chemotherapy-related nausea, multiple-sclerosis spasticity and some pain outcomes, reviews report possible benefit for particular preparations, often balanced by adverse effects and only modest average improvement.'], evidence: 'supported', citationIds: ['solmi-2023'] },
        { id: 'where-evidence-is-weak', title: 'Where evidence is weak, mixed or absent', paragraphs: ['Claims involving cancer cure, broad immune “balancing,” general prevention, depression, anxiety and many inflammatory conditions often outrun controlled human evidence. Symptom relief is also different from treating the underlying disease.', 'Preclinical anticancer activity is not proof that cannabis treats cancer in people. Replacing oncology care with concentrated extracts can delay effective treatment and create toxicity or interaction risks.'], evidence: 'established', citationIds: ['solmi-2023'] },
        { id: 'benefit-harm-balance', title: 'Benefits and harms belong in the same calculation', paragraphs: ['Dizziness, somnolence, cognitive effects, nausea, diarrhoea, psychiatric effects and withdrawal can matter even when an average symptom score improves. Long-term evidence is thinner than short-term trial evidence for many products.', 'A clinically useful decision considers baseline risk, realistic effect size, alternatives, monitoring, stopping rules and patient values—not whether cannabis is described as natural or medical.'], evidence: 'established', citationIds: ['solmi-2023', 'ahrq-2025'] },
        { id: 'scope', title: 'Education, not a prescription', paragraphs: ['Efifya can explain evidence and support better questions, but it cannot diagnose a condition or recommend a personal treatment plan. Medical decisions require a qualified clinician who can consider medicines, pregnancy, cardiovascular and mental-health history, age, and other risks.'], callout: { title: 'Urgent care', body: 'Seek emergency help for chest pain, seizures, severe confusion, loss of consciousness, breathing difficulty, or persistent vomiting and dehydration.', tone: 'safety' } },
      ] },
      { slug: 'synthetic-cannabinoids', title: 'Synthetic cannabinoids and “Colorado”', summary: 'Why unknown sprayed products can be substantially more dangerous than plant cannabis.', duration: '16 min', objectives: ['Distinguish synthetic cannabinoid receptor agonists from plant cannabis', 'Explain why street names cannot identify composition', 'Recognize an emergency and respond safely'], keyTerms: ['Synthetic cannabinoid', 'Receptor agonist', 'Toxicity', 'Adulterant', 'Contamination'], reviewedAt: '16 July 2026', sections: [
        { id: 'unknown-products', title: 'A name is not a chemical test', paragraphs: ['Street names are inconsistent. Products sold as “Colorado,” “Spice,” “K2” or other names may contain different synthetic compounds, high-potency cannabis, mixtures or contaminants. The same name can describe different products in different places or at different times.', 'Appearance, smell and packaging cannot establish chemical identity. Dried plant material may simply be a carrier onto which active chemicals were applied, sometimes unevenly. This can create large dose differences within one packet.'], evidence: 'supported', citationIds: ['nap-2024'] },
        { id: 'why-risk-differs', title: 'Why the risk can differ from cannabis', paragraphs: ['Many synthetic cannabinoid receptor agonists interact with cannabinoid receptors differently from THC and may produce stronger or less predictable effects. The category includes numerous compounds with different potencies, metabolites and toxicities.', 'Reported harms can involve the brain, heart, kidneys and gastrointestinal system. Severe agitation, psychosis, seizures, loss of consciousness and cardiovascular complications are possible. A reassuring previous experience does not identify the next product.'], evidence: 'supported', citationIds: ['nap-2024'] },
        { id: 'emergency-response', title: 'Recognise and respond to an emergency', paragraphs: ['Call local emergency services for seizures, collapse, chest pain, severe agitation, breathing difficulty, very high temperature, loss of consciousness or severe confusion. Tell responders what is known about the product, timing, amount and any other substances without guessing the chemistry.', 'Keep the person away from traffic, heights and sharp objects. Do not restrain a seizure, place anything in the mouth, force fluids or induce vomiting. If unconscious but breathing, place them on their side when safe and monitor breathing until help arrives.'], evidence: 'established', citationIds: ['nap-2024'], callout: { title: 'Emergency signs', body: 'Seizures, collapse, chest pain, breathing difficulty, loss of consciousness or severe confusion require urgent medical help.', tone: 'safety' } },
        { id: 'harm-reduction', title: 'Reducing uncertainty', paragraphs: ['The safest option is not to use an unknown product. Do not rely on a seller’s label, assume one batch matches another or use alone. Combining unknown cannabinoids with alcohol, stimulants, opioids or sedatives adds risk and complicates emergency care.', 'Health messaging should not state that every product called “Colorado” is one particular chemical. The accurate warning is that the name does not establish composition and that some products sold under it may contain dangerous synthetic cannabinoids or other adulterants.'], evidence: 'supported', citationIds: ['nap-2024'] },
      ] },
      { slug: 'cannabinoid-hyperemesis-syndrome', title: 'Cannabinoid hyperemesis syndrome', summary: 'Recurrent vomiting associated with prolonged cannabis exposure, diagnostic uncertainty and when to seek urgent care.', duration: '22 min', objectives: ['Recognize the typical CHS pattern', 'Understand the limits of symptom-based diagnosis', 'Respond to dehydration and emergency signs', 'Describe why cessation is central'], keyTerms: ['Hyperemesis', 'Prodromal phase', 'Dehydration', 'Differential diagnosis', 'Cessation'], reviewedAt: '16 July 2026', sections: [
        { id: 'what-is-chs', title: 'What CHS is—and is not', paragraphs: ['Cannabinoid hyperemesis syndrome is a clinical pattern of recurrent nausea, abdominal pain and vomiting reported in some people with prolonged cannabis exposure. It is not the same as an ordinary short-lived adverse reaction, and not everyone with heavy use develops it.', 'No single symptom proves the diagnosis. Clinicians must consider pregnancy, infection, medication effects, gastrointestinal disease, metabolic problems, neurological causes and other emergencies.'], evidence: 'supported', citationIds: ['kirk-chs-2026'] },
        { id: 'patterns', title: 'Patterns reported by patients', paragraphs: ['The course is often described in prodromal, hyperemetic and recovery phases, though real experiences do not always fit neatly. Repeated hot showers or baths are commonly reported but are neither universal nor specific enough to confirm CHS.', 'Dr. Riley Kirk and colleagues used a survey-based approach to examine symptom profiles and patterns of cannabis administration. The study adds community-informed detail but, as observational self-report research, cannot by itself establish prevalence or prove causation.'], evidence: 'preliminary', citationIds: ['kirk-chs-2026'], callout: { title: 'Researcher lens: Dr. Riley Kirk', body: 'This study demonstrates how lived experience can refine clinical questions while still requiring careful interpretation of study design and bias.', tone: 'note' } },
        { id: 'acute-care', title: 'Vomiting can become dangerous', paragraphs: ['Persistent vomiting can cause dehydration, electrolyte disturbance, kidney injury and aspiration risk. Very little urine, fainting, confusion, severe weakness, blood in vomit, chest pain, fever or inability to keep fluids down requires urgent assessment.', 'Hot bathing may temporarily relieve symptoms for some people, but prolonged very hot bathing can worsen dehydration or cause burns. It is not a substitute for medical care.'], evidence: 'established', citationIds: ['kirk-chs-2026'], callout: { title: 'Seek urgent care', body: 'Repeated vomiting with dehydration, confusion, fainting, severe pain or reduced urination needs prompt medical assessment.', tone: 'safety' } },
        { id: 'recovery', title: 'Cessation, recovery and recurrence', paragraphs: ['Sustained cessation of cannabinoid exposure is central to preventing recurrence when CHS is the correct diagnosis. Changing strain, route or THC percentage is not a proven solution, and products marketed as CBD may still contain cannabinoids or inaccurate labels.', 'Stopping can be difficult when cannabis is used for sleep, pain, anxiety or dependence. Nonjudgmental clinical support should address withdrawal, the original reason for use and alternative care rather than treating the person as irresponsible.'], evidence: 'supported', citationIds: ['kirk-chs-2026'] },
      ] },
      { slug: 'dependence-tolerance-and-withdrawal', title: 'Dependence, tolerance & withdrawal', summary: 'How repeated use can change response, when use becomes a disorder, and what supportive care looks like.', duration: '24 min', objectives: ['Distinguish tolerance, dependence and cannabis use disorder', 'Recognize withdrawal and functional impairment', 'Identify evidence-aware support options'], keyTerms: ['Tolerance', 'Withdrawal', 'Craving', 'Cannabis use disorder', 'Motivational interviewing'], reviewedAt: '16 July 2026', sections: [
        { id: 'definitions', title: 'Three related but different concepts', paragraphs: ['Tolerance means a person needs more exposure for a similar effect. Physical dependence means adaptation produces symptoms when use stops. A use disorder is a pattern of impaired control, risk and continued use despite meaningful harm.', 'Tolerance or withdrawal can occur without every feature of a severe disorder. Conversely, a person can experience serious functional harm even without dramatic physical withdrawal.'], evidence: 'established', citationIds: ['nap-2024'] },
        { id: 'signs', title: 'Recognising problematic use', paragraphs: ['Warning signs include using more than intended, unsuccessful attempts to reduce, craving, substantial time devoted to use, neglecting roles, hazardous use and continuing despite physical, psychological or relationship problems.', 'Frequency alone does not diagnose a disorder, but frequent high-THC exposure and younger age of initiation are important risk signals. Assessment should consider function, control, context and consequences.'], evidence: 'supported', citationIds: ['nap-2024'] },
        { id: 'withdrawal', title: 'Withdrawal and the first weeks', paragraphs: ['Withdrawal may include irritability, sleep disruption, vivid dreams, anxiety, low appetite, restlessness and physical discomfort. Symptoms vary and can overlap with the reason cannabis was originally used.', 'Severe psychiatric symptoms, suicidality, inability to care for oneself or dangerous polysubstance withdrawal require professional assessment. Cannabis withdrawal is usually not medically dangerous in the same way as alcohol or benzodiazepine withdrawal, but distress can be substantial.'], evidence: 'supported', citationIds: ['nap-2024'] },
        { id: 'support', title: 'Support works better than shame', paragraphs: ['Evidence supports behavioural approaches such as motivational enhancement, cognitive behavioural strategies and contingency management more than a single established medication. Goals may include cessation or structured reduction depending on safety and clinical context.', 'A useful plan identifies triggers, changes access and routines, protects sleep, recruits supportive people, treats co-occurring conditions and prepares for lapses without treating them as total failure.'], evidence: 'supported', citationIds: ['nap-2024'], callout: { title: 'MedGriot field note', body: 'Your essay’s emphasis on nonjudgmental community support fits here, after revising claims so intention complements—rather than replaces—chemical and clinical risk reduction.', tone: 'note' } },
      ] },
      { slug: 'pregnancy-youth-and-vulnerability', title: 'Pregnancy, youth & other vulnerability', summary: 'Why risk is not evenly distributed and when precaution should be stronger.', duration: '23 min', objectives: ['Explain pregnancy and adolescent concerns', 'Identify cardiovascular and psychiatric vulnerability', 'Use non-stigmatising risk communication'], keyTerms: ['Pregnancy', 'Lactation', 'Neurodevelopment', 'Psychosis vulnerability', 'Precaution'], reviewedAt: '16 July 2026', sections: [
        { id: 'pregnancy', title: 'Pregnancy and lactation', paragraphs: ['THC crosses the placenta and cannabinoids can enter breast milk. Observational evidence is complicated by tobacco, other substances and social factors, but professional guidance advises cessation during pregnancy and lactation because safety is not established and adverse outcomes are a concern.', 'People may use cannabis for nausea, sleep or distress. Effective counselling should address those needs, offer alternatives and avoid punitive approaches that deter prenatal care.'], evidence: 'established', citationIds: ['acog-2025'] },
        { id: 'adolescence', title: 'Adolescence and brain development', paragraphs: ['Adolescence is a period of ongoing brain development and greater vulnerability to dependence. Earlier initiation and frequent use are associated with educational, cognitive and mental-health risks, although individual outcomes vary and observational confounding matters.', 'Prevention should be accurate and credible. Exaggerated claims can undermine trust, while normalising frequent high-potency use can hide meaningful risk.'], evidence: 'supported', citationIds: ['nap-2024', 'cooper-potency-2025'] },
        { id: 'mental-cardiovascular', title: 'Mental-health and cardiovascular vulnerability', paragraphs: ['People with a personal or family history of psychosis, bipolar disorder or severe panic may face greater risk from high-THC exposure. Cannabis is not a single cause of psychosis, but dose, frequency, age and vulnerability affect the association.', 'THC can change heart rate and blood pressure and may provoke symptoms in susceptible people. Chest pain, fainting, severe palpitations or neurological symptoms require medical assessment rather than reassurance based on cannabis being natural.'], evidence: 'supported', citationIds: ['solmi-2023'] },
        { id: 'communication', title: 'Risk communication without stigma', paragraphs: ['Higher vulnerability is not a moral failure. Ask what is being used, why, how often, what benefits are perceived, what harms have occurred and what support is acceptable.', 'Confidential, person-centred conversations improve disclosure. Threats and punishment can push use underground and make product, pregnancy and mental-health risks harder to address.'], evidence: 'supported', citationIds: ['acog-2025'], callout: { title: 'Clinical guidance', body: 'Pregnant, breastfeeding or medically vulnerable people should receive individual advice from qualified healthcare professionals.', tone: 'safety' } },
      ] },
    ] }],
  },
  {
    slug: 'nigeria-law-and-policy', number: '04', title: 'Nigeria: Law & Policy', shortTitle: 'Nigeria policy',
    description: 'Read Nigerian cannabis policy accurately by separating enacted law, enforcement, reform proposals, advocacy and public-health strategy.', level: 'Intermediate', accent: '#79a7d3',
    modules: [{ title: 'Legal literacy', description: 'Understand status, institutions and responsible policy interpretation.', lessons: [
      { slug: 'how-to-read-nigerian-cannabis-law', title: 'How to read Nigerian cannabis law', summary: 'A practical framework for distinguishing statutes, amendments, enforcement statements and policy proposals.', duration: '22 min', objectives: ['Distinguish law from policy advocacy', 'Check legal status and dates', 'Recognize the limits of public legal information'], keyTerms: ['Statute', 'Amendment', 'Enforcement', 'Policy proposal'], reviewedAt: '16 July 2026', sections: [
        { id: 'status-first', title: 'Begin with legal status', paragraphs: ['A political speech, committee recommendation, pilot proposal or advocacy campaign does not change the law by itself. Reliable legal education identifies the controlling instrument, its amendments, commencement, jurisdiction and current status before describing practical consequences.'], evidence: 'established', citationIds: ['nap-2024'], callout: { title: 'Legal information, not advice', body: 'Cannabis remains legally controlled in Nigeria. Anyone facing a specific legal problem should consult qualified Nigerian counsel and current official texts.', tone: 'nigeria' } },
        { id: 'institutions', title: 'Institutions have different roles', paragraphs: ['Legislatures make and amend statutes; courts interpret law; enforcement agencies implement statutory mandates; ministries and regulators may develop policy within delegated powers. Mixing these roles can turn a proposal or enforcement opinion into a false statement of law.'], evidence: 'established', citationIds: ['nap-2024'] },
        { id: 'source-check', title: 'Build a legal source chain', paragraphs: ['Start with the official text, then locate amendments, subsidiary regulations and relevant court decisions. A news article, agency post or advocacy brief may explain context but should not replace the controlling legal source.', 'Record the jurisdiction and verification date. A rule from another country—or a state within a federal system—does not automatically apply in Nigeria. Historical penalties also should not be described as current without checking later amendments.'], evidence: 'established', citationIds: ['nap-2024'] },
        { id: 'practical-reading', title: 'Read definitions, offences and powers separately', paragraphs: ['Legal documents often define the controlled material, prohibited conduct, available exemptions, enforcement powers and penalties in different sections. Quoting a penalty without the offence elements can mislead.', 'Public legal education should also distinguish possession, cultivation, supply, import or export, prescribed medicines, industrial crops and research permissions rather than treating “cannabis law” as one rule.'], evidence: 'supported', citationIds: ['nap-2024'], callout: { title: 'Verification rule', body: 'Before publishing a time-sensitive Nigerian legal claim, Efifya should require an official source, status label and last-checked date.', tone: 'nigeria' } },
      ] },
      { slug: 'policy-models-and-public-health', title: 'Policy models & public health', summary: 'Compare prohibition, decriminalisation, medical access and regulated adult-use models without collapsing them into “legalisation.”', duration: '24 min', objectives: ['Name major policy models', 'Compare public-health safeguards', 'Identify equity considerations'], keyTerms: ['Decriminalisation', 'Medical access', 'Regulation', 'Health equity'], reviewedAt: '16 July 2026', sections: [
        { id: 'models', title: 'Policy exists on a spectrum', paragraphs: ['Decriminalising possession, permitting prescribed cannabinoid medicines, licensing industrial hemp and regulating adult-use cannabis are distinct interventions. Each changes different behaviours, institutions, markets and health risks.'], evidence: 'established', citationIds: ['nap-2024'] },
        { id: 'evaluation', title: 'Judge outcomes, not labels', paragraphs: ['Policy evaluation should track product exposure, youth access, impaired driving, poisonings, treatment access, enforcement burden, market displacement and unequal impacts. A policy can improve one outcome while worsening another.'], evidence: 'supported', citationIds: ['nap-2024'] },
        { id: 'regulatory-tools', title: 'Regulation is a bundle of choices', paragraphs: ['Age limits, product testing, potency rules, taxation, packaging, marketing restrictions, outlet density, public-use rules, impaired-driving enforcement and surveillance can produce very different systems under the same legal label.', 'Medical access also varies: approved cannabinoid medicines, specialist prescribing, broader authorisation and retail “medical” markets are not equivalent in product quality or evidence.'], evidence: 'established', citationIds: ['nap-2024'] },
        { id: 'equity', title: 'Equity requires measurement', paragraphs: ['Reform can reduce arrests yet leave past convictions, unequal enforcement and barriers to legal participation untouched. Conversely, commercial expansion can concentrate profits without repairing communities most affected by prohibition.', 'A Nigerian framework would need locally defined measures of health, livelihoods, enforcement, agriculture, youth protection and access to treatment—not imported assumptions that another country’s results will transfer unchanged.'], evidence: 'supported', citationIds: ['nap-2024'], callout: { title: 'MedGriot reading', body: '“Politics and reform attempts on cannabis in Nigeria” and “Where we go from here” can serve as editorial reflections after every legal claim is linked to a dated primary source.', tone: 'note' } },
      ] },
    ] }],
  },
  {
    slug: 'cultivation-and-quality', number: '05', title: 'Cultivation & Product Quality', shortTitle: 'Cultivation',
    description: 'Study plant development, environmental variables, harvest quality and contamination through a legal, safety-conscious lens.', level: 'Intermediate', accent: '#9cc26d',
    modules: [{ title: 'Plant to product', description: 'Connect cultivation decisions to chemistry, quality and risk.', lessons: [
      { slug: 'environment-and-plant-development', title: 'Environment & plant development', summary: 'How light, water, nutrients, temperature, humidity, genetics and stress shape plant growth.', duration: '24 min', objectives: ['Identify major growth variables', 'Separate plant morphology from effect claims', 'Recognize local legal constraints'], keyTerms: ['Photoperiod', 'Vapour pressure', 'Phenotype', 'Substrate'], reviewedAt: '16 July 2026', sections: [
        { id: 'interaction', title: 'Genetics meets environment', paragraphs: ['Observed plant traits emerge from interactions between inherited potential and the growing environment. Height, flowering time, disease susceptibility and chemical composition cannot be attributed to a single “sativa” or “indica” label.'], evidence: 'supported', citationIds: ['ditchfield-2014'] },
        { id: 'context', title: 'Cultivation is locally regulated', paragraphs: ['Agronomic knowledge does not override law. Climate-specific discussion should also avoid assuming that all West African plants share one genetic or chemical profile.'], callout: { title: 'Nigeria context', body: 'This lesson teaches plant science. It is not an instruction or authorisation to cultivate a controlled plant.', tone: 'nigeria' } },
        { id: 'light-water-rootzone', title: 'Light, water and the root zone', paragraphs: ['Light intensity and duration influence photosynthesis and development, while excessive light or heat can stress tissue. Water management must balance plant demand with oxygen availability around roots; both chronic saturation and severe drying can impair function.', 'Substrate physical properties, pH and dissolved salts influence nutrient availability, but one “perfect” number does not apply across every substrate, stage or measurement method. Symptoms can have multiple causes and should not be diagnosed from a photograph alone.'], evidence: 'supported', citationIds: ['ditchfield-2014'] },
        { id: 'climate-disease', title: 'Climate, pests and disease pressure', paragraphs: ['Temperature and humidity shape transpiration, development and pathogen risk. Dense flowers in humid conditions may be vulnerable to mould, while poor sanitation and infected propagation material can spread pests and pathogens.', 'Integrated pest management prioritises prevention, monitoring, biological knowledge and least-harmful controls. Applying unapproved pesticides to a product intended for inhalation can create residues and thermal breakdown products not considered in ordinary food use.'], evidence: 'supported', citationIds: ['ditchfield-2014'], callout: { title: 'Research context', body: 'Dr. Riley Kirk’s Bioactive discussions on tissue culture, pathogen testing, soil biology and mycotoxins are useful expert supplements, not substitutes for validated standards.', tone: 'note' } },
      ] },
      { slug: 'quality-contaminants-and-testing', title: 'Quality, contaminants & testing', summary: 'Why appearance, smell and strain names cannot replace validated composition and contaminant testing.', duration: '23 min', objectives: ['Name major contaminant categories', 'Interpret a certificate of analysis cautiously', 'Recognize the limits of sensory inspection'], keyTerms: ['Certificate of analysis', 'Pesticide', 'Mycotoxin', 'Residual solvent'], reviewedAt: '16 July 2026', sections: [
        { id: 'quality', title: 'Quality is measurable', paragraphs: ['Product quality includes identity, cannabinoid composition, microbial burden, pesticides, heavy metals, residual solvents, moisture and stability. A visually attractive flower or familiar name does not establish safety or potency.'], evidence: 'established', citationIds: ['nap-2024', 'cooper-barriers-2021'], callout: { title: 'Researcher lens: Sue Sisley', body: 'Study-product quality affects whether clinical findings resemble the products people actually encounter. Institutional profiles are treated as context; efficacy conclusions still come from published trials and reviews.', tone: 'note' } },
        { id: 'testing', title: 'A report is only as good as the sample', paragraphs: ['Laboratory reports should identify the sample, methods, laboratory, dates and measured limits. Results from one batch should not be transferred to another product, and a certificate should be checked for authenticity and scope.'], evidence: 'supported', citationIds: ['nap-2024'], callout: { title: 'Unknown products', body: 'If composition is unknown, avoid making medical, potency or safety assumptions from packaging, colour, smell or street name.', tone: 'safety' } },
        { id: 'contaminants', title: 'Contaminants have different pathways', paragraphs: ['Microbes and mycotoxins may arise during cultivation, drying or storage. Heavy metals can enter from soil, water or inputs. Pesticides may be intentionally applied or environmentally present. Residual solvents relate to extraction and inadequate purging.', 'A test panel that covers one category does not establish freedom from every other hazard. Pass/fail limits also depend on jurisdiction, method performance and intended route of use.'], evidence: 'established', citationIds: ['nap-2024'] },
        { id: 'coa', title: 'Read a certificate of analysis', paragraphs: ['Check the laboratory identity and accreditation scope, sample or batch identifier, collection and test dates, methods, units, detection limits and whether results are on a dry- or as-received basis. Confirm that totals are calculated transparently.', 'Potency precision can be overstated, and incentives may encourage laboratory shopping. A certificate is evidence about the tested sample under stated methods—not a permanent guarantee about every package.'], evidence: 'supported', citationIds: ['nap-2024'] },
      ] },
      { slug: 'harvest-drying-curing-and-stability', title: 'Harvest, drying, curing & stability', summary: 'How post-harvest handling changes moisture, microbes, aroma and measured chemistry.', duration: '22 min', objectives: ['Describe major post-harvest transformations', 'Explain water activity and microbial risk', 'Recognize why simple harvest rules are unreliable'], keyTerms: ['Water activity', 'Drying', 'Curing', 'Decarboxylation', 'Oxidation'], reviewedAt: '16 July 2026', sections: [
        { id: 'harvest', title: 'Harvest is a sampling decision', paragraphs: ['Plant tissues and glandular trichomes do not mature uniformly. A harvest decision balances intended product characteristics, disease pressure, plant health and analytical goals rather than one universal count of brown stigmas.', 'Sampling location and method matter because chemical composition can vary within a plant and crop. A small analysed sample may not describe every flower equally.'], evidence: 'supported', citationIds: ['ditchfield-2014'] },
        { id: 'drying', title: 'Drying controls moisture and risk', paragraphs: ['Drying removes water and changes texture, aroma and chemical stability. Drying too slowly under unsuitable conditions can support mould; excessive heat or rapid drying can accelerate loss of volatile compounds and damage quality.', 'Water activity is more informative for microbial stability than moisture percentage alone because it reflects water available for biological processes. Safe targets depend on validated standards and product type.'], evidence: 'supported', citationIds: ['nap-2024'] },
        { id: 'curing', title: 'What curing can—and cannot—do', paragraphs: ['Curing describes controlled storage after initial drying to equalise moisture and allow continued chemical and sensory change. It cannot remove pesticides, heavy metals, mycotoxins or an established microbial hazard.', 'A pleasant smell is not evidence of microbiological safety. Containers, handling hygiene, temperature, humidity and time affect whether storage preserves or degrades a product.'], evidence: 'supported', citationIds: ['ditchfield-2014'] },
        { id: 'stability', title: 'Chemistry continues to change', paragraphs: ['Acidic cannabinoids can decarboxylate with heat and time, while THC can oxidise into other compounds. Volatile terpenes may evaporate or oxidise, changing aroma independently of safety.', 'Stability claims require defined packaging, temperature, light, oxygen and time. Home formulas promising exact potency from time and temperature alone cannot account for starting composition, particle size, equipment variation and losses.'], evidence: 'supported', citationIds: ['nap-2024'], callout: { title: 'Legal and safety scope', body: 'This is post-harvest science, not authorisation to cultivate or manufacture a controlled product.', tone: 'nigeria' } },
      ] },
    ] }],
  },
  {
    slug: 'history-culture-and-society', number: '06', title: 'History, Culture & Society', shortTitle: 'History & culture',
    description: 'Explore cannabis across medicine, agriculture, ritual, colonial prohibition, language, stigma and contemporary reform.', level: 'Foundation', accent: '#c99bc8',
    modules: [{ title: 'Context and interpretation', description: 'Study cultural knowledge without turning tradition into clinical proof.', lessons: [
      { slug: 'cannabis-across-cultures', title: 'Cannabis across cultures', summary: 'A careful introduction to historical uses, cultural meanings and the limits of retrospective claims.', duration: '24 min', objectives: ['Distinguish historical use from clinical evidence', 'Recognize cultural diversity', 'Avoid romanticising or dismissing traditional knowledge'], keyTerms: ['Ethnobotany', 'Prohibition', 'Stigma', 'Traditional knowledge'], reviewedAt: '16 July 2026', sections: [
        { id: 'many-histories', title: 'There is no single cannabis history', paragraphs: ['Cannabis has been used for fibre, seed, medicine, intoxication and ritual in different places and periods. Historical records vary in quality, and modern product categories should not be projected backward without evidence.'], evidence: 'supported', citationIds: ['ditchfield-2014'] },
        { id: 'tradition', title: 'Respect is not the same as proof', paragraphs: ['Traditional use can generate research questions and preserve important cultural knowledge. It does not by itself establish modern clinical efficacy, safe dosage or product equivalence. Both uncritical celebration and automatic dismissal obscure what the evidence can actually show.'], evidence: 'established', citationIds: ['solmi-2023'] },
        { id: 'movement', title: 'Movement, exchange and changing meanings', paragraphs: ['Plants, seeds, fibres, preparations and knowledge moved through trade, migration, conquest and colonial systems. Uses changed as cannabis entered new languages, religions, medical systems and commodity markets.', 'Claims of a single ancient origin story or unchanged traditional practice should be treated cautiously. Archaeological evidence, texts, linguistic evidence and later folklore do not all carry the same certainty.'], evidence: 'supported', citationIds: ['ditchfield-2014'] },
        { id: 'colonialism', title: 'Colonialism and prohibition', paragraphs: ['Modern prohibition developed through international control, colonial governance, racialised narratives, medical professionalisation and political interests—not from one scientific finding. Local enforcement histories differ and should be reconstructed from primary legal and archival sources.', 'Acknowledging political history does not make contemporary health risks imaginary. A mature curriculum can examine both the harms of punitive policy and the genuine risks of products, impairment and dependence.'], evidence: 'supported', citationIds: ['nap-2024'] },
      ] },
      { slug: 'stigma-language-and-media', title: 'Stigma, language & media', summary: 'How terminology, racialised narratives, sensational reporting and commercial hype influence cannabis beliefs.', duration: '20 min', objectives: ['Recognize framing and stigma', 'Use person-first language', 'Evaluate competing narratives'], keyTerms: ['Framing', 'Stigma', 'Misinformation', 'Commercial bias'], reviewedAt: '16 July 2026', sections: [
        { id: 'frames', title: 'Language shapes the debate', paragraphs: ['Cannabis communication has been shaped by criminalisation, racial and class stereotypes, medical advocacy and commercial promotion. Evidence-aware language avoids defining people by use and avoids replacing prohibition-era exaggeration with wellness-industry exaggeration.'], evidence: 'supported', citationIds: ['nap-2024'] },
        { id: 'media', title: 'Ask what a story leaves out', paragraphs: ['A responsible reader checks the product, population, comparison, outcome, time period, funding and absolute size of an effect. Headlines often omit these details whether they promote benefit or warn of harm.'], evidence: 'established', citationIds: ['nap-2024'] },
        { id: 'person-first', title: 'Use language that preserves personhood', paragraphs: ['Terms that reduce people to a criminal category or stereotype can increase shame and discourage care. Person-first descriptions—such as a person who uses cannabis or a person with cannabis use disorder—are usually more precise.', 'Context still matters: communities may reclaim language, while legal texts may use older terms. Quotation and historical analysis should explain rather than silently reproduce stigma.'], evidence: 'supported', citationIds: ['nap-2024'] },
        { id: 'two-hypes', title: 'Avoid prohibition hype and wellness hype', paragraphs: ['Prohibition messaging may imply that any exposure guarantees ruin. Commercial messaging may imply that a natural plant is broadly curative and safe. Both erase dose, product, vulnerability and uncertainty.', 'A useful correction does not merely reverse the slogan. It states the strongest supported conclusion, its limits and what evidence would change confidence.'], evidence: 'established', citationIds: ['nap-2024'], callout: { title: 'MedGriot editorial lane', body: 'Your essays can make the Nigerian stakes vivid, while adjacent evidence notes show which claims are data, interpretation or advocacy.', tone: 'note' } },
      ] },
      { slug: 'cannabis-in-africa-and-nigeria', title: 'Cannabis in Africa & Nigeria', summary: 'A cautious historical framework for movement, local use, colonial control and modern Nigerian narratives.', duration: '25 min', objectives: ['Avoid unsupported origin stories', 'Connect colonial law to modern policy', 'Distinguish archival evidence from oral history', 'Identify research gaps'], keyTerms: ['Archive', 'Oral history', 'Colonial law', 'Indian hemp', 'Political economy'], reviewedAt: '16 July 2026', sections: [
        { id: 'evidence-problem', title: 'The historical evidence is uneven', paragraphs: ['African cannabis histories draw on archaeology, botany, trade records, colonial archives, language and oral knowledge. Each source preserves some experiences and excludes others. Colonial records may document control more reliably than ordinary use.', 'A responsible account marks uncertainty instead of repeating a precise arrival date or single diffusion route without strong evidence. Local terminology can also change meaning across time and place.'], evidence: 'supported', citationIds: ['ditchfield-2014'] },
        { id: 'use-and-livelihood', title: 'Use, exchange and livelihood', paragraphs: ['Cannabis has intersected with medicine, labour, recreation, ritual, trade and subsistence in different African settings. These uses should not be homogenised into one “African tradition.”', 'Illicit status shapes what is documented: farmers, consumers and healers may avoid researchers, while enforcement statistics overrepresent what police detect rather than total production or use.'], evidence: 'preliminary', citationIds: ['nap-2024'] },
        { id: 'colonial-nigeria', title: 'Colonial categories and Nigerian prohibition', paragraphs: ['The label “Indian hemp” and legal controls reflect transnational and colonial histories rather than a neutral botanical classification. Later Nigerian law and enforcement developed within both domestic politics and international drug-control systems.', 'A complete legal timeline must verify the exact text, amendments and current status of each instrument. Stories about past death penalties, enforcement powers or reform proposals should never be copied without checking controlling sources.'], evidence: 'supported', citationIds: ['nap-2024'], callout: { title: 'MedGriot series', body: 'Your three essays provide contemporary Nigerian interpretation. They should be presented as authored editorial work, accompanied by a legal fact-check and primary-source timeline.', tone: 'note' } },
        { id: 'research-agenda', title: 'What Nigeria still needs to know', paragraphs: ['Major gaps include representative use patterns, product composition, synthetic adulterants, treatment access, cultivation livelihoods, enforcement disparities, public attitudes and locally relevant health outcomes.', 'Community-informed research can identify urgent questions, while analytical chemistry, epidemiology, qualitative methods and legal scholarship test different parts. The lack of local data should produce humility—not permission to import foreign conclusions unchanged.'], evidence: 'established', citationIds: ['nap-2024'] },
      ] },
    ] }],
  },
];

